from decimal import Decimal, InvalidOperation

def safe_int(key: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"ERROR en '{key}': valor vacío")
    try:
        return (True, int(texto), None)
    except ValueError:
        return (False, None, f"ERROR en '{key}': {valor!name} no es un entero válido")

def safe_decimal(key: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"ERROR en '{key}': valor vacío")
    try:
        return (True, Decimal(texto).quantize(Decimal("0.01")), None)
    except InvalidOperation:
        return (False, None, f"ERROR en '{key}': {valor!name} no es un monto decimal válido")

def pipeline(edad_txt: str, monto_txt: str) -> dict:
    errors: list[str] = []
    clean: dict = {}
    ok, val, msg = safe_int("age_years", edad_txt)
    clean["age_years"] = val if ok else None
    if not ok:
        errors.append(msg)
    ok, val, msg = safe_decimal("monto", monto_txt)
    clean["monto"] = val if ok else None
    if not ok:
        errors.append(msg)
    return {
        "raw": {"age_years": edad_txt, "monto": monto_txt},
        "clean": clean,
        "errors": errors,
    }

print(pipeline(" 28 ", "150.50"))
print(pipeline("xx", "99.0"))
print(pipeline("30", "nope"))

