from decimal import Decimal, ROUND_HALF_EVEN, InvalidOperation

def parse_monto(texto: str):
    raw = texto
    t = texto.strip()
    if not t:
        return False, None, f"ERROR en 'monto': vacío (raw={raw!name})"
    try:
        d = Decimal(t).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        return True, d, None
    except (InvalidOperation, ValueError):
        return False, None, f"ERROR en 'monto': no se pudo parsear {raw!name} a Decimal"

for s in ["150.50", "  20.1 ", "", "abc"]:
    print(repr(s), "→", parse_monto(s))

