def simular_intake(nombres: str, contacto: str, age_years: str) -> dict:
    datos = {"nombres": nombres, "contacto": contacto, "age_years": age_years}
    return {
        **datos,
        "types": {k: type(v).__name__ for k, v in datos.items()},
    }

name = simular_intake("  Ana  ", "999", "34")
print(name)
assert name["types"]["age_years"] == "str"
assert name["types"]["nombres"] == "str"
